/*
  Global design tokens and base styles
  Visual style derived from the provided academic profile design:
  - Minimal, text-first layout
  - White background, dark gray body text
  - Strong orange accent for active navigation
*/

:root {
  /* Brand colors */
  --color-primary-500: #F26722; /* main orange (active nav background) */
  --color-primary-600: #C94E12;

  --color-secondary-blue: #0645AD;
  --color-secondary-purple: #92278F;

  --color-neutral-0: #FFFFFF;
  --color-neutral-700: #333333; /* main body text */
  --color-neutral-500: #777777; /* secondary text */
  --color-neutral-200: #E0E0E0; /* light borders */

  /* Semantic colors */
  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #ED6C02;
  --color-info: #0277BD;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 28px;
  --font-size-h2: 20px;
  --font-size-h3: 18px;
  --font-size-body: 15px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.25;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (multiples of 4px / 8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Layout */
  --layout-max-width: 960px;
}

* {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-700);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-secondary-blue);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

/* Layout wrappers */

.wrapper {
  max-width: var(--layout-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--space-5);  /* approximates left margin seen in design */
  padding-right: var(--space-5);
}

/* Header and primary navigation */

.site-header {
  background-color: var(--color-neutral-0);
}

.header-inner {
  padding-top: var(--space-5);   /* space above name */
  padding-bottom: var(--space-4);
}

.site-identity {
  margin-bottom: var(--space-4); /* gap between name block and nav */
}

.site-title {
  margin: 0 0 var(--space-1) 0;
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-bold);
  line-height: var(--line-height-tight);
}

.site-title-link {
  color: var(--color-neutral-700);
  text-decoration: none;
}

.site-title-link:hover,
.site-title-link:focus {
  text-decoration: underline;
}

.site-tagline {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
}

.primary-nav {
  border-top: none; /* stays visually light, no bar in original */
}

.primary-nav-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: center; /* matches centered nav tabs */
  list-style: none;
  margin: 0;
  padding: 0;
  gap: 0; /* no extra gaps between items; padding is on links */
}

.primary-nav-item {
  margin: 0;
}

.primary-nav-link {
  display: inline-block;
  padding: 8px 16px; /* approx: 8px vertical x 16px horizontal */
  font-family: var(--font-heading);
  font-size: var(--font-size-small);
  font-weight: var(--font-weight-semibold);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--color-primary-500);
  background-color: transparent;
  border-radius: 0;
}

.primary-nav-link:hover,
.primary-nav-link:focus {
  background-color: rgba(242, 103, 34, 0.06);
  text-decoration: none;
}

.primary-nav-link--active {
  background-color: var(--color-primary-500);
  color: var(--color-neutral-0);
}

.primary-nav-link--active:hover,
.primary-nav-link--active:focus {
  background-color: var(--color-primary-600);
}

/* Main content area */

.site-main {
  padding-bottom: var(--space-6);
}

.main-inner {
  padding-top: var(--space-4); /* space between nav and main text */
}

.site-main p {
  margin-top: 0;
  margin-bottom: var(--space-3); /* ~16px between paragraphs */
}

.site-main h2,
.site-main h3,
.site-main h4 {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  margin-top: var(--space-4);
  margin-bottom: var(--space-2);
}

.site-main h2 {
  font-size: var(--font-size-h2);
}

.site-main h3 {
  font-size: var(--font-size-h3);
}

code,
pre {
  font-family: var(--font-code);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-neutral-200);
  padding-top: var(--space-3);
  padding-bottom: var(--space-4);
  background-color: var(--color-neutral-0);
}

.footer-inner {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.footer-nav-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  column-gap: var(--space-3);
  row-gap: var(--space-1);
}

.footer-nav-item {
  margin: 0;
}

.footer-nav-link {
  font-size: var(--font-size-small);
  color: var(--color-neutral-700);
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-primary-500);
  text-decoration: none;
}

.footer-meta {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-neutral-500);
}

/* Simple responsiveness */

@media (max-width: 640px) {
  .wrapper {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .header-inner {
    padding-top: var(--space-4);
  }

  .primary-nav-list {
    justify-content: flex-start;
  }
}
